INSERT INTO public.pages (slug, title, content, meta_description) VALUES
  ('about', 'Hakkımızda', '<section style="padding: 60px 24px;"><h2>Hakkımızda</h2><p>Aspiyas Teknoloji ve Ticaret A.Ş. olarak yapay zeka odaklı medya ve teknoloji alanlarında yenilikçi ürünler üretiyoruz. SaaS yazılım, medya prodüksiyon, AI destekli mobil uygulamalar ve dijital pazarlama hizmetleri sunuyoruz.</p><p>Ekibimiz, Türkiye ve global pazarlarda müşterilerimize en iyi çözümleri sunmak için çalışıyor.</p></section>', 'Aspiyas Teknoloji hakkında bilgi edinin. Yapay zeka odaklı medya ve teknoloji çözümleri.'),
  ('services', 'Hizmetlerimiz', '<section style="padding: 60px 24px;"><h2>Hizmetlerimiz</h2><p>Yenilikçi teknolojiler ve hizmetler sunuyoruz:</p><ul><li>SaaS Yazılım Projeleri</li><li>Medya ve Prodüksiyon</li><li>AI Destekli Mobil Uygulamalar</li><li>Dijital Pazarlama</li></ul><p>Her projede müşteri odaklı, ölçeklenebilir çözümler üretiyoruz.</p></section>', 'Aspiyas hizmetleri: SaaS, medya prodüksiyon, AI mobil uygulamalar, dijital pazarlama.'),
  ('contact', 'İletişim', '<section style="padding: 60px 24px;"><h2>İletişim</h2><p>Projenizi konuşalım. İstanbul merkezli ekibimizle Türkiye ve global pazarlarda ürün, içerik ve büyüme süreçleri tasarlıyoruz.</p><p><strong>E-posta:</strong> info@aspiyas.com</p><p><strong>Telefon:</strong> +90 212 000 00 00</p><p><strong>Adres:</strong> Maslak, İstanbul</p></section>', 'Aspiyas ile iletişime geçin. İstanbul merkezli teknoloji holdingi.')
